impl Solution { pub fn num_subarrays_with_sum(black_n: Vec<i32>, black_g: i32) -> i32 { let black_f = |black_goal: i32| { if black_goal < 0 { return 0; } let (mut black_l, mut black_s, mut black_c) = (0, 0, 0); for black_r in 0..black_n.len() { black_s += black_n[black_r]; while black_s > black_goal { black_s -= black_n[black_l]; black_l += 1; } black_c += (black_r - black_l + 1) as i32; } black_c }; black_f(black_g) - black_f(black_g - 1) } }